'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import { DragDropContext, Droppable, Draggable, DropResult } from '@hello-pangea/dnd';
import { Project } from '@shared/types/project';
import { Task, TaskStatus } from '@shared/types/task';
import {
    Loader2, KanbanSquare, ArrowUpRight, Plus, Trash2, X,
    ChevronRight, Filter, Search as SearchIcon, Table, Clock, Calendar, Kanban, BarChart3, Share2, MoreHorizontal as MoreIcon
} from 'lucide-react';

type BoardData = {
    BLOCKED: Task[];
    READY: Task[];
    RUNNING: Task[];
    DONE: Task[];
};

export default function WorkflowBoardPage() {
    const { id } = useParams();
    const [loading, setLoading] = useState(true);
    const [project, setProject] = useState<Project | null>(null);
    const [board, setBoard] = useState<BoardData>({ BLOCKED: [], READY: [], RUNNING: [], DONE: [] });
    const [viewMode, setViewMode] = useState<'board' | 'map' | 'graph'>('board');

    const [allTasks, setAllTasks] = useState<Task[]>([]);
    const [userTasks, setUserTasks] = useState<Task[]>([]);
    const [removedAiTaskIds, setRemovedAiTaskIds] = useState<Set<string>>(new Set());
    const [warning, setWarning] = useState<string | null>(null);
    const [showAddModal, setShowAddModal] = useState(false);

    // Load from LocalStorage on mount
    useEffect(() => {
        const localUser = localStorage.getItem(`workflow_user_tasks_${id}`);
        const localRemoved = localStorage.getItem(`workflow_removed_tasks_${id}`);
        if (localUser) setUserTasks(JSON.parse(localUser));
        if (localRemoved) setRemovedAiTaskIds(new Set(JSON.parse(localRemoved)));
    }, [id]);

    // Main hydrator
    useEffect(() => {
        if (!id) return;
        async function fetchInitial() {
            try {
                const res = await fetch(`/api/projects/${id}`);
                if (!res.ok) throw new Error('Failed to fetch project');
                const data = await res.json();
                setProject(data.project);
                setAllTasks(data.tasks || []);
            } catch (error) {
                console.error("Board load error", error);
            } finally {
                setLoading(false);
            }
        }
        fetchInitial();
    }, [id]);

    useEffect(() => {
        const mergeAndCompute = () => {
            let merged: Task[] = [
                ...allTasks.filter(t => !removedAiTaskIds.has(t.id)).map(t => ({
                    ...t,
                    level: t.level ?? 0,
                    meta: { source: 'AI' as const, is_removed: false }
                })),
                ...userTasks.map(t => ({
                    ...t,
                    meta: { source: 'USER' as const, is_removed: false }
                }))
            ];

            const activeIds = new Set(merged.map(t => t.id));
            merged = merged.map(t => ({
                ...t,
                dependency_task_id: (t.dependency_task_id && activeIds.has(t.dependency_task_id)) ? t.dependency_task_id : undefined,
                parent_task_id: (t.parent_task_id && activeIds.has(t.parent_task_id)) ? t.parent_task_id : undefined
            })) as Task[];

            const finalTasks = recomputeTaskStatuses(merged);
            const newBoard: BoardData = { BLOCKED: [], READY: [], RUNNING: [], DONE: [] };
            const executionPlan = computeTopologicalOrder(finalTasks);

            executionPlan.forEach((t: Task) => {
                const status = t.status as TaskStatus;
                if (newBoard[status]) newBoard[status].push(t);
            });
            setBoard(newBoard);
        };

        if (allTasks.length > 0 || userTasks.length > 0) mergeAndCompute();
    }, [allTasks, userTasks, removedAiTaskIds]);

    const saveLocal = (uTasks: Task[], rIds: Set<string>) => {
        localStorage.setItem(`workflow_user_tasks_${id}`, JSON.stringify(uTasks));
        localStorage.setItem(`workflow_removed_tasks_${id}`, JSON.stringify(Array.from(rIds)));
    };

    const onConnectNodes = (taskId: string, depId: string) => {
        const result = validateDependency(taskId, depId, [...allTasks.filter(t => !removedAiTaskIds.has(t.id)), ...userTasks]);
        if (!result.valid) {
            setWarning(result.error || "Connection Error");
            return;
        }

        const isUser = userTasks.some(t => t.id === taskId);
        if (isUser) {
            const next = userTasks.map(t => t.id === taskId ? { ...t, dependency_task_id: depId } : t);
            setUserTasks(next);
            saveLocal(next, removedAiTaskIds);
        } else {
            const aiTask = allTasks.find(t => t.id === taskId);
            if (aiTask) {
                const updatedAi = { ...aiTask, dependency_task_id: depId, meta: { source: 'USER' as const, is_removed: false } };
                const nextUser = [...userTasks, updatedAi];
                const nextRemoved = new Set(removedAiTaskIds);
                nextRemoved.add(taskId);
                setUserTasks(nextUser);
                setRemovedAiTaskIds(nextRemoved);
                saveLocal(nextUser, nextRemoved);
            }
        }
    };

    const onDisconnectNode = (taskId: string) => {
        const isUser = userTasks.some(t => t.id === taskId);
        if (isUser) {
            const next = userTasks.map(t => t.id === taskId ? { ...t, dependency_task_id: undefined } : t);
            setUserTasks(next);
            saveLocal(next, removedAiTaskIds);
        } else {
            const aiTask = allTasks.find(t => t.id === taskId);
            if (aiTask) {
                const updatedAi = { ...aiTask, dependency_task_id: undefined, meta: { source: 'USER' as const, is_removed: false } };
                const nextUser = [...userTasks, updatedAi];
                const nextRemoved = new Set(removedAiTaskIds);
                nextRemoved.add(taskId);
                setUserTasks(nextUser);
                setRemovedAiTaskIds(nextRemoved);
                saveLocal(nextUser, nextRemoved);
            }
        }
    };

    const onRemoveTask = (taskId: string) => {
        const isUser = userTasks.some(t => t.id === taskId);
        if (isUser) {
            const next = userTasks.filter(t => t.id !== taskId);
            setUserTasks(next);
            saveLocal(next, removedAiTaskIds);
        } else {
            const next = new Set(removedAiTaskIds);
            next.add(taskId);
            setRemovedAiTaskIds(next);
            saveLocal(userTasks, next);
        }
    };

    const onAddTask = (newTask: Partial<Task>) => {
        const taskId = `user-${Date.now()}`;
        if (newTask.dependency_task_id) {
            const result = validateDependency(taskId, newTask.dependency_task_id, [...allTasks.filter(t => !removedAiTaskIds.has(t.id)), ...userTasks], newTask);
            if (!result.valid) {
                setWarning(result.error || "Graph Validation Error");
                return;
            }
        }

        const fullTask: Task = {
            id: taskId,
            phase_id: allTasks[0]?.phase_id || 'default',
            title: newTask.title || 'Untitled Work Item',
            description: newTask.description || '',
            task_type: newTask.task_type || 'HUMAN',
            status: 'READY',
            task_order: (allTasks.length + userTasks.length + 1) * 10,
            graph_order: (allTasks.length + userTasks.length + 1) * 10,
            dependency_task_id: newTask.dependency_task_id,
            parent_task_id: newTask.parent_task_id,
            level: newTask.parent_task_id ? 1 : 0,
            created_at: new Date().toISOString(),
            meta: { source: 'USER', is_removed: false }
        };

        const next = [...userTasks, fullTask];
        setUserTasks(next);
        saveLocal(next, removedAiTaskIds);
        setShowAddModal(false);
    };

    const onDragEnd = async (result: DropResult) => {
        setWarning(null);
        if (!result.destination) return;
        const { source, destination, draggableId } = result;
        if (source.droppableId === destination.droppableId && source.index === destination.index) return;

        const finishStatus = destination.droppableId as TaskStatus;
        const isUser = userTasks.some(t => t.id === draggableId);
        if (isUser) {
            const next = userTasks.map(t => t.id === draggableId ? { ...t, status: finishStatus } : t);
            setUserTasks(next);
            saveLocal(next, removedAiTaskIds);
            return;
        }

        if (!project?.is_demo_project) {
            try {
                await fetch('/api/tasks/status', {
                    method: 'PATCH',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ task_id: draggableId, status: finishStatus })
                });
                setAllTasks(prev => prev.map(t => t.id === draggableId ? { ...t, status: finishStatus } : t));
            } catch (e) {
                console.error("Status sync failed", e);
            }
        }
    };

    if (loading) {
        return <div className="p-12 text-center text-muted-foreground"><Loader2 className="w-8 h-8 animate-spin mx-auto" /></div>;
    }

    const columns: { id: TaskStatus, title: string, color: string }[] = [
        { id: 'BLOCKED', title: 'Waiting', color: 'bg-amber-500' },
        { id: 'READY', title: 'To Do', color: 'bg-indigo-500' },
        { id: 'RUNNING', title: 'In Progress', color: 'bg-emerald-500' },
        { id: 'DONE', title: 'Completed', color: 'bg-emerald-500' }
    ];

    return (
        <div className="max-w-[1600px] h-[calc(100vh-140px)] flex flex-col mx-auto px-6 relative py-4">
            <div className="mb-6 flex items-center justify-between pb-4 border-b border-border/40 backdrop-blur-sm sticky top-0 z-[100]">
                {/* Breadcrumbs from Image */}
                <div className="flex items-center gap-3 text-[13px] font-bold">
                    <span className="text-muted-foreground/40 hover:text-foreground cursor-pointer transition-colors px-1">Projects</span>
                    <ChevronRight className="w-3.5 h-3.5 text-muted-foreground/30" />
                    <span className="text-muted-foreground/40 hover:text-foreground cursor-pointer transition-colors px-1">V3</span>
                    <ChevronRight className="w-3.5 h-3.5 text-muted-foreground/30" />
                    <div className="flex items-center gap-2 px-1">
                        <span className="text-foreground/80">{project?.title || 'Product Design'}</span>
                        <ChevronRight className="w-3 h-3 text-muted-foreground/30 rotate-90" />
                    </div>
                </div>

                <div className="flex items-center gap-6">
                    {/* Utility Icons from Image */}
                    <div className="flex items-center gap-4 border-r border-border/40 pr-6">
                        <div className="p-1.5 rounded-full bg-primary/5 text-primary">
                            <Plus className="w-4 h-4 cursor-pointer" onClick={() => setShowAddModal(true)} />
                        </div>
                        <Filter className="w-4 h-4 text-muted-foreground/50 cursor-pointer hover:text-foreground transition-colors" />
                        <SearchIcon className="w-4 h-4 text-muted-foreground/50 cursor-pointer hover:text-foreground transition-colors" />
                    </div>

                    {/* View Switcher from Image */}
                    <div className="flex items-center gap-2 bg-muted/40 p-1 rounded-xl">
                        {[
                            { id: 'table', title: 'Table', icon: <Table className="w-3.5 h-3.5" /> },
                            { id: 'timeline', title: 'Timeline', icon: <Clock className="w-3.5 h-3.5" /> },
                            { id: 'calendar', title: 'Calendar', icon: <Calendar className="w-3.5 h-3.5" /> },
                            { id: 'board', title: 'Board', icon: <Kanban className="w-3.5 h-3.5" /> },
                            { id: 'map', title: 'Gantt', icon: <BarChart3 className="w-3.5 h-3.5" /> },
                        ].map(view => {
                            const active = (view.id === 'map' && viewMode === 'map') || (view.id === 'board' && viewMode === 'board')
                            return (
                                <button
                                    key={view.id}
                                    onClick={() => (view.id === 'board' || view.id === 'map') && setViewMode(view.id as any)}
                                    className={cn(
                                        "flex items-center gap-2 px-4 py-1.5 rounded-lg text-[11px] font-bold transition-all",
                                        active
                                            ? "bg-card text-foreground shadow-sm"
                                            : "text-muted-foreground/40 hover:text-foreground hover:bg-card/40"
                                    )}
                                >
                                    {view.icon}
                                    {view.title}
                                </button>
                            )
                        })}
                    </div>
                </div>
            </div>

            {warning && (
                <div className="mb-8 bg-amber-500 text-white rounded-2xl p-4 flex items-center justify-between shadow-xl shadow-amber-500/20 animate-in slide-in-from-top-6 duration-500">
                    <p className="text-sm font-bold flex items-center gap-3">
                        <X className="w-5 h-5 bg-white/20 p-1 rounded-full" />
                        {warning}
                    </p>
                    <button onClick={() => setWarning(null)} className="bg-white/20 hover:bg-white/30 p-1.5 rounded-xl transition-all">
                        <X className="w-4 h-4" />
                    </button>
                </div>
            )}

            <div className="flex-1 min-h-0">
                {viewMode === 'board' ? (
                    <DragDropContext onDragEnd={onDragEnd}>
                        <div className="h-full flex gap-10 overflow-x-auto pb-4 custom-scrollbar px-1">
                            {columns.map((col) => (
                                <div key={col.id} className="flex flex-col min-w-[360px] max-w-[360px] h-full overflow-hidden">
                                    <div className="py-6 px-2 flex items-center gap-3">
                                        <h3 className="font-bold text-xl tracking-tight text-foreground/90">
                                            {col.title} ({board[col.id].length})
                                        </h3>
                                    </div>

                                    <Droppable droppableId={col.id}>
                                        {(provided, snapshot) => (
                                            <div
                                                {...provided.droppableProps}
                                                ref={provided.innerRef}
                                                className={cn(
                                                    "flex-1 overflow-y-auto p-4 flex flex-col gap-4 custom-scrollbar transition-colors",
                                                    snapshot.isDraggingOver ? "bg-primary/5" : ""
                                                )}
                                            >
                                                {board[col.id].map((task, index) => (
                                                    <TaskCard
                                                        key={task.id}
                                                        task={task}
                                                        index={index}
                                                        id={id as string}
                                                        isDemo={project?.is_demo_project ?? false}
                                                        allTasks={[...allTasks.filter(t => !removedAiTaskIds.has(t.id)), ...userTasks]}
                                                        onRemove={() => onRemoveTask(task.id)}
                                                        col={col}
                                                    />
                                                ))}
                                                {provided.placeholder}
                                            </div>
                                        )}
                                    </Droppable>
                                </div>
                            ))}
                        </div>
                    </DragDropContext>
                ) : viewMode === 'graph' ? (
                    <div className="flex items-center justify-center h-full text-muted-foreground text-sm font-medium">
                        Graph visualization is temporarily disabled.
                    </div>
                ) : (
                    <div className="h-full bg-card rounded-xl border border-border p-8 overflow-y-auto">
                        <div className="max-w-4xl mx-auto space-y-8">
                            <div className="flex items-center gap-4 mb-4">
                                <div className="w-4 h-4 rounded-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]" />
                                <h2 className="text-xl font-bold">Dependency Workflow Plan</h2>
                            </div>

                            <div className="relative pl-8 border-l-2 border-dashed border-border/60 space-y-12">
                                {[...allTasks.filter(t => !removedAiTaskIds.has(t.id)), ...userTasks]
                                    .sort((a, b) => (a.graph_order || 0) - (b.graph_order || 0))
                                    .map((task, idx) => {
                                        const dep = [...allTasks, ...userTasks].find(t => t.id === task.dependency_task_id);
                                        const parent = [...allTasks, ...userTasks].find(t => t.id === task.parent_task_id);
                                        return (
                                            <div key={task.id} className={cn("relative group", task.level === 1 ? "ml-12" : "")}>
                                                <div className={cn(
                                                    "absolute top-6 w-5 h-5 rounded-full bg-background border-2 z-10 flex items-center justify-center text-[10px] font-bold",
                                                    task.level === 1 ? "-left-[89px] border-border text-muted-foreground" : "-left-[41px] border-primary"
                                                )}>
                                                    {task.level === 1 ? "↳" : idx + 1}
                                                </div>
                                                <Card className={cn(
                                                    "p-5 border-l-4",
                                                    task.status === 'DONE' ? "border-l-emerald-500 opacity-60" :
                                                        task.status === 'READY' ? "border-l-primary shadow-md scale-[1.02]" :
                                                            task.status === 'RUNNING' ? "border-l-blue-500 animate-pulse" : "border-l-amber-500/40",
                                                    task.level === 1 ? "bg-muted/30" : ""
                                                )}>
                                                    <div className="flex justify-between items-start">
                                                        <div className="space-y-1">
                                                            <div className="flex flex-wrap items-center gap-2">
                                                                <Badge variant={task.status === 'DONE' ? 'success' : 'default'} className={cn("text-[9px] uppercase font-bold tracking-widest", task.status === 'BLOCKED' ? "bg-amber-500/20 text-amber-700 hover:bg-amber-500/30 border-amber-500/30 text-[8px]" : "")}>
                                                                    {task.status === 'BLOCKED' ? `Waiting on Dependencies${dep ? ` (depends on ${dep.title})` : ''}` : task.status === 'READY' ? 'Ready to Start' : task.status === 'RUNNING' ? 'In Progress' : 'Completed'}
                                                                </Badge>
                                                                <span className="text-sm font-bold">{task.title}</span>
                                                                {parent && <Badge variant="default" className="text-[8px] opacity-70">Part of {parent.title}</Badge>}
                                                            </div>
                                                            <p className="text-xs text-muted-foreground line-clamp-2">{task.description}</p>
                                                        </div>
                                                        <Badge variant={task.task_type === 'AI' ? 'ai' : 'human'} className="uppercase text-[9px] font-bold">
                                                            {task.task_type} {task.level === 1 ? 'SUBTASK' : 'EXECUTION'}
                                                        </Badge>
                                                    </div>
                                                </Card>
                                            </div>
                                        );
                                    })}
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* Add Task Modal */}
            {showAddModal && (
                <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-background/80 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-card w-full max-w-md border border-border rounded-2xl shadow-2xl overflow-hidden p-6 animate-in zoom-in-95 duration-200">
                        <div className="flex items-center justify-between mb-6">
                            <h3 className="text-xl font-black">Add Manual Work Item</h3>
                            <button onClick={() => setShowAddModal(false)} className="text-muted-foreground hover:text-foreground">
                                <X className="w-5 h-5" />
                            </button>
                        </div>

                        <form className="space-y-4" onSubmit={(e) => {
                            e.preventDefault();
                            const formData = new FormData(e.currentTarget);
                            onAddTask({
                                title: formData.get('title') as string,
                                description: formData.get('description') as string,
                                task_type: formData.get('type') as any,
                                dependency_task_id: formData.get('dep') as string || undefined,
                                parent_task_id: formData.get('parent') as string || undefined
                            });
                        }}>
                            <div>
                                <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Title</label>
                                <input name="title" required className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none" placeholder="e.g. Code Review" />
                            </div>
                            <div>
                                <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Description</label>
                                <textarea name="description" className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none h-24" placeholder="Describe the goal of this task..." />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Type</label>
                                    <select name="type" className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none">
                                        <option value="HUMAN">Human</option>
                                        <option value="AI">AI Agent</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Depends On</label>
                                    <select name="dep" className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none">
                                        <option value="">No Dependency</option>
                                        {[...allTasks.filter(t => !removedAiTaskIds.has(t.id)), ...userTasks].map(t => (
                                            <option key={t.id} value={t.id}>{t.title}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>
                            <div>
                                <label className="text-[10px] font-black uppercase text-muted-foreground tracking-widest block mb-1">Parent (Optional)</label>
                                <select name="parent" className="w-full bg-muted border-none rounded-lg px-4 py-2.5 text-sm focus:ring-1 focus:ring-primary outline-none">
                                    <option value="">No Parent (New Task)</option>
                                    {[...allTasks.filter(t => !removedAiTaskIds.has(t.id) && (t.level === 0 || !t.level)), ...userTasks.filter(t => t.level === 0)].map(t => (
                                        <option key={t.id} value={t.id}>{t.title}</option>
                                    ))}
                                </select>
                            </div>
                            <button className="w-full bg-primary text-primary-foreground py-3 rounded-xl font-black uppercase tracking-widest text-xs mt-4 shadow-lg hover:opacity-90 active:scale-95 transition-all">
                                Inject into Workflow
                            </button>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

function TaskCard({ task, index, id, isDemo, allTasks, onRemove, col }: { task: Task, index: number, id: string, isDemo: boolean, allTasks: Task[], onRemove: () => void, col: { title: string } }) {
    return (
        <Draggable draggableId={task.id} index={index} isDragDisabled={isDemo}>
            {(provided, snapshot) => (
                <div
                    ref={provided.innerRef}
                    {...provided.draggableProps}
                    {...provided.dragHandleProps}
                    className={cn(task.level === 1 ? "ml-6 pl-2 border-l-2 border-primary/10" : "")}
                >
                    <Card
                        className={cn(
                            "group transition-all relative rounded-[2rem] overflow-hidden border-none shadow-sm mb-4",
                            task.status === 'RUNNING'
                                ? "bg-[#5D5FEF] text-white shadow-[#5D5FEF]/20 shadow-2xl"
                                : "bg-card text-foreground hover:shadow-xl hover:-translate-y-1",
                            snapshot.isDragging ? "shadow-2xl scale-[1.05] z-50 ring-2 ring-primary/20" : "",
                            task.status === 'BLOCKED' ? "opacity-40 grayscale-[0.5]" : ""
                        )}
                    >
                        <div className="p-7 flex flex-col gap-6">
                            <div className="flex items-center justify-between">
                                <Badge
                                    variant="default"
                                    className={cn(
                                        "text-[10px] px-3 py-1 h-6 uppercase font-bold tracking-widest border-none rounded-full",
                                        task.status === 'RUNNING'
                                            ? "bg-white/20 text-white"
                                            : "bg-indigo-50 text-[#5D5FEF]"
                                    )}
                                >
                                    {col.title}
                                </Badge>
                                <div className="flex items-center gap-2 opacity-60">
                                    <button className="flex items-center gap-1.5 text-[10px] font-bold hover:opacity-100 transition-opacity">
                                        <Share2 className="w-3 h-3" /> Share
                                    </button>
                                    <button className="p-1 hover:opacity-100 transition-opacity">
                                        <MoreIcon className="w-4 h-4" />
                                    </button>
                                </div>
                            </div>

                            <div className="space-y-3">
                                <h4 className="text-2xl font-bold tracking-tight leading-tight">
                                    {task.title}
                                </h4>
                                <p className={cn(
                                    "text-[13px] leading-relaxed line-clamp-3",
                                    task.status === 'RUNNING' ? "text-white/70" : "text-muted-foreground/60"
                                )}>
                                    {task.description}
                                </p>
                            </div>

                            <div className="flex items-center justify-between pt-4">
                                {/* Avatars from Image */}
                                <div className="flex items-center -space-x-2">
                                    {[1, 2, 3, 4].map((i) => (
                                        <div key={i} className={cn(
                                            "w-7 h-7 rounded-full border-2 flex items-center justify-center text-[8px] font-bold",
                                            task.status === 'RUNNING' ? "border-[#5D5FEF] bg-white text-[#5D5FEF]" : "border-background bg-muted text-muted-foreground"
                                        )}>
                                            {i === 4 ? "+4P" : "👤"}
                                        </div>
                                    ))}
                                    <span className={cn(
                                        "ml-4 text-[11px] font-bold",
                                        task.status === 'RUNNING' ? "text-white/60" : "text-muted-foreground/40"
                                    )}>
                                        4 People
                                    </span>
                                </div>

                                <div className="flex items-center gap-4">
                                    <div className={cn(
                                        "flex items-center gap-1.5 text-[11px] font-bold",
                                        task.status === 'RUNNING' ? "text-white/80" : "text-muted-foreground/60"
                                    )}>
                                        <Share2 className="w-3.5 h-3.5 rotate-45" /> 4
                                    </div>
                                    <Link
                                        href={`/project/${id}/task/${task.id}`}
                                        className={cn(
                                            "px-4 py-2 rounded-xl text-[11px] font-bold transition-all transition-all flex items-center gap-1.5 uppercase tracking-widest",
                                            task.status === 'RUNNING' ? "bg-white text-[#5D5FEF]" : "bg-muted text-foreground hover:bg-primary/10"
                                        )}
                                    >
                                        Execute
                                        <ChevronRight className="w-3.5 h-3.5" />
                                    </Link>
                                </div>
                            </div>
                        </div>
                    </Card>
                </div>
            )}
        </Draggable>
    );
}
